from __future__ import annotations

from typing import Optional


def greet(name: str, times: int = 1) -> str:
    """Return a greeting repeated `times` times."""
    return (f"Hello, {name}! " * times).strip()


def find_user(user_id: int) -> Optional[str]:
    """Return user name or None if not found."""
    users: dict[int, str] = {1: "Alice", 2: "Bob"}
    return users.get(user_id)

from __future__ import annotations

from typing import Union


def normalise(value: int | float | str) -> float:
    """Accept int, float, or string and return a float."""
    if isinstance(value, str):
        # type checker knows value is str here
        return float(value.replace(",", ""))
    # type checker knows value is int | float here
    return float(value)


Result = Union[str, dict[str, object]]


def process_tool_response(response: Result) -> str:
    if isinstance(response, dict):
        # narrowed to dict[str, object]
        return str(response.get("content", ""))
    # narrowed to str
    return response


# Demonstrate that the type checker enforces the contract
print(normalise("1,234.56"))   # 1234.56
print(normalise(42))           # 42.0
print(normalise(3.14))         # 3.14

from __future__ import annotations

from dataclasses import dataclass, field
from typing import Callable, Optional


# --- Domain types ---

@dataclass
class LLMRequest:
    prompt: str
    model: str
    max_tokens: int = 1024
    temperature: float = 0.7
    system: Optional[str] = None


@dataclass
class LLMResponse:
    content: str
    model: str
    input_tokens: int
    output_tokens: int
    stop_reason: str


# A backend is any callable that accepts a request and returns a response.
Backend = Callable[[LLMRequest], LLMResponse]


# --- Router ---

class LLMRouter:
    def __init__(self) -> None:
        self._backends: dict[str, Backend] = {}
        self._call_log: list[tuple[str, int, int]] = []   # (model, in, out)

    def register(self, name: str, backend: Backend) -> None:
        self._backends[name] = backend

    def route(self, request: LLMRequest) -> LLMResponse:
        backend: Backend = self._backends[request.model]
        response: LLMResponse = backend(request)
        self._call_log.append(
            (response.model, response.input_tokens, response.output_tokens)
        )
        return response

    def total_tokens(self) -> int:
        return sum(inp + out for _, inp, out in self._call_log)


# --- Stub backend for illustration ---

def mock_backend(req: LLMRequest) -> LLMResponse:
    return LLMResponse(
        content=f"Response to: {req.prompt[:30]}...",
        model=req.model,
        input_tokens=len(req.prompt.split()),
        output_tokens=20,
        stop_reason="end_turn",
    )


router = LLMRouter()
router.register("claude-3-5-sonnet-20241022", mock_backend)

resp = router.route(LLMRequest(prompt="Summarise this text", model="claude-3-5-sonnet-20241022"))
print(resp.content)
print(f"Total tokens used: {router.total_tokens()}")

from typing import Any

# Bad: silences all type errors for `data`
def handle_response(data: Any) -> Any:
    return data["choices"][0]["message"]["content"]

# Better: use a TypedDict or dataclass that mirrors the real shape
from typing import TypedDict

class Choice(TypedDict):
    message: dict[str, str]

class OpenAIResponse(TypedDict):
    choices: list[Choice]

def handle_response(data: OpenAIResponse) -> str:
    return data["choices"][0]["message"]["content"]
